---@class LNewbieEventCtrl
local LNewbieEventCtrl = LxClass("LNewbieEventCtrl",nil)

function LNewbieEventCtrl:LNewbieEventCtrl(manager)
    self._manager = manager
    self._eventClassMaps = {
        [LNewbieEventType.PLOT] = "LNewbiePlotEvent",
        [LNewbieEventType.BG] = "LNewbieUIEvent",
        [LNewbieEventType.BLACK] = "LNewbieUIEvent",
        [LNewbieEventType.ONCE_EFFECT] = "LNewbieUIEvent",
        [LNewbieEventType.LOOP_EFFECT] = "LNewbieUIEvent",
        [LNewbieEventType.CREATE_ROLE] = "LNewbieUIEvent",
        [LNewbieEventType.BATTLE] = "LNewbieBattleEvent",
        [LNewbieEventType.SPECIAL] = "LNewbieUIEvent",
        [LNewbieEventType.TALK] = "LNewbieUIEvent",
        [LNewbieEventType.JUMP] = "LNewbieUIEvent",
    }

    ---@type table<number, LNewbieEventBase>
    self._storyEventMap = {}
    ---@type LNewbieEventBase[]
    self._eventList = {}
end

---@return LNewbieEventBase
function LNewbieEventCtrl:GetStoryEvent(eventId, curTime)
    local ref = GameTable.StoryNewbieRef[eventId]
    if not ref then
        if LOG_INFO_ENABLED then
            printInfoN("[newbie] StoryNewbie 不存在配置 refId = "..tostring(eventId))
        end
        return nil
    end
    local eventClass = self._eventClassMaps[ref.type]
    local event
    if eventClass then
        event = LxRequire("LApp.gameplay.Newbie.Object."..eventClass):New(self:GetManager())
    end
    if event then
        event:Create(eventId,curTime)
    end
    return event
end

function LNewbieEventCtrl:InitStoryEvent(storyId)
    self._initStoryId = storyId
    self._waitInit = true
end

function LNewbieEventCtrl:StartInitStoryEvent(time)
    local eventId = tonumber(self._initStoryId)
    local event = self:GetStoryEvent(eventId, time)
    if event then
        table.insert(self._eventList, event)
        self._storyEventMap[eventId] = event
        event:Start()
    end
end

function LNewbieEventCtrl:CheckNextEvent(eventIds, time)
    for k,v in ipairs(eventIds) do
        local ref = GameTable.StoryNewbieRef[v]
        if ref then
            local nextArr = string.split(ref.next, ",") or {}
            for m,eventId in ipairs(nextArr) do
                eventId = tonumber(eventId)
                if eventId > 0 then
                    local event = self:GetStoryEvent(eventId, time)
                    if event then
                        table.insert(self._eventList, event)
                        self._storyEventMap[eventId] = event
                        event:Start()
                    end
                end
            end
        end
    end
end

function LNewbieEventCtrl:OnRun(time)
    if self._isEventFinished then
        return
    end

    if self._waitInit then
        self._waitInit = nil
        self:StartInitStoryEvent(time)
    end

    if not self._eventList then return end

    local endIdxs = {}
    for k,v in ipairs(self._eventList) do
        v:OnRun(time)
        if v:IsEnd() then
            table.insert(endIdxs, k)
        end
    end

    local len = #endIdxs
    if len > 0 then
        local nextEventIds = {}
        for k=len, 1, -1 do
            local idx = endIdxs[k]
            local event = self._eventList[idx]
            table.remove(self._eventList, idx)
            local eventId = event:GetEventId()
            event = self._storyEventMap[eventId]
            self._storyEventMap[eventId] = nil
            event:Destroy()
            table.insert(nextEventIds, eventId)
        end
        self:CheckNextEvent(nextEventIds, time)
    end

    if #self._eventList == 0 then
        self._isEventFinished = true
    end
end

function LNewbieEventCtrl:ClearEvent(list)
    for k,v in pairs(list) do
        local event = self._storyEventMap[v]
        if event then
            event:End()
        end
    end
end

function LNewbieEventCtrl:Destroy()
    table.removeall(self)
end

function LNewbieEventCtrl:GetManager()
    return self._manager
end

function LNewbieEventCtrl:IsFinished()
    return self._isEventFinished
end

function LNewbieEventCtrl:OnEventEnd(eventId)
    if not self._storyEventMap then return end
    local event = self._storyEventMap[eventId]
    if event then
        event:End()
    end
end

return LNewbieEventCtrl